<script setup lang="ts">import type{ApiResponse,CatalogOverview}from"@moecraft/shared";const config=useRuntimeConfig();const{data,error,pending}=await useAsyncData("public-catalog",()=>$fetch<ApiResponse<CatalogOverview>>(`${config.public.apiBase}/catalog/public`).then(response=>response.resultData));const groups=computed(()=>[{key:"categories",title:"热门类目",items:data.value?.categories??[]},{key:"brands",title:"品牌馆",items:data.value?.brands??[]},{key:"franchises",title:"作品 / IP",items:data.value?.franchises??[]}]);useSeoMeta({title:"手办目录、品牌与作品 IP - MoeCraft",description:"浏览 MoeCraft 手办商城的多级类目、品牌和作品 IP 聚合目录。"});</script>
<template><main><header><small>DISCOVER MOECRAFT</small><h1>探索手办世界</h1><p>从类目、品牌与喜爱的作品出发，找到属于你的收藏。</p></header><p v-if="pending" class="state">正在加载目录…</p><p v-else-if="error" class="state">目录暂时无法加载。</p><section v-for="group in groups" v-else :key="group.key"><div class="heading"><h2>{{group.title}}</h2><span>{{group.items.length}} 项</span></div><div class="grid"><NuxtLink v-for="item in group.items" :key="item.id" :to="`/${group.key}/${item.slug}`"><small>{{item.nameEnUs||'MOECRAFT'}}</small><h3>{{item.nameZhCn}}</h3><p>{{item.productCount}} 件商品</p></NuxtLink></div></section></main></template>
